@mm_3orass.proof
def prove_mm_3orass(proof: TheoryProofAuthor) -> CompleteProof:
    from metamath_setmm_provider.shards.s001 import bitri
    from metamath_setmm_provider.shards.s004 import orass


    _step_1 = proof.use(
        df_3or,
        subst={
            "ph": "ph",
            "ps": "ps",
            "ch": "ch",
        },
    )  # ⊢ wb(w3o(ph, ps, ch), wo(wo(ph, ps), ch))
    _step_2 = proof.use(
        orass,
        subst={
            "ph": "ph",
            "ps": "ps",
            "ch": "ch",
        },
    )  # ⊢ wb(wo(wo(ph, ps), ch), wo(ph, wo(ps, ch)))
    _step_3 = proof.use(bitri, _step_1, _step_2)  # ⊢ wb(w3o(ph, ps, ch), wo(ph, wo(ps, ch)))
    return proof.qed(_step_3)


